import React from 'react'

export const Footer = () => {

  let footerStyle   = {
      position: "relative",
      top: "70vh",
     // bottom: "0vh",
      width: "100%"
  }

  return (
    <div className='bg-dark text-light'  style={footerStyle}>
        <p className='text-center'>
          Copyright &copy; MyTodosList.com
        </p>
    </div>
  )
}
